const items = $input.all();
if (items.length === 0) {
  return [{ json: { isValid: false, error: "Empty input payload" } }];
}
const body = items[0].json;

let isValid = true;
let errorReason = "";

const required = ['scheme_id', 'scheme_name', 'category', 'data'];
for (const field of required) {
  if (body[field] === undefined || body[field] === null) {
    isValid = false;
    errorReason = `Missing required field: ${field}`;
    break;
  }
}

if (isValid) {
  const data = body.data;
  if (!data.nav_history || !Array.isArray(data.nav_history) || !data.holdings || !Array.isArray(data.holdings) || !data.risk_metrics || typeof data.risk_metrics !== 'object') {
    isValid = false;
    errorReason = "Field 'data' must contain nav_history (array), holdings (array), and risk_metrics (object)";
  }
}

return [{
  json: {
    ...body,
    isValid: isValid,
    error: errorReason
  }
}];

const items = $input.all();
const errorReason = items[0]?.json?.error || "Unknown validation error";

return [{
  json: {
    success: false,
    error: errorReason
  }
}];

